// AlfaOBD seed-key tests.
//
// Pinned vectors were generated by running the reference JS impl from
// `attached_assets/alfaobd_seedkey_1776573875649.js` (which is itself a
// 1:1 port of `alfaobd_seedkey_1776573875649.py`) against the seed list
// shared with the SGW XTEA tests. Re-generate by running:
//
//   node --input-type=module -e "import('./attached_assets/...js').then(...)"
//
// (the one-shot generator script lives in this PR's commit message).
//
// All assertions are byte-for-byte against those pinned outputs. Any
// drift here means the JS port in `src/lib/algos.js` no longer matches
// the reference, which is a regression.
import test from "node:test";
import assert from "node:assert/strict";
import {
  alfaHt, alfaF, alfaAo, alfaW6, alfaW6By,
  unlockKey, unlockKeyBytes,
  ALFA_XTEA_DELTA, ALFA_XTEA_ROUNDS, ALFA_XTEA_KEY,
  SGW_XTEA_KEY,
  ALGOS, UNLOCK_FALLBACK, pickUnlockChain,
} from "../lib/algos.js";
import { AOBD_W6, AOBD_W7, AOBD_W7_UNVERIFIED, AOBD_DISPATCH, AOBD_META }
  from "../lib/alfaobdAlgorithms.generated.js";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const SEEDS = [
  "00000000","12345678","DEADBEEF","FFFFFFFF",
  "CAFEBABE","A1B2C3D4","00112233",
];
const hex = (u8) => Array.from(u8).map(b => b.toString(16).padStart(2,"0")).join("").toUpperCase();
const bytes = (s) => {
  const r = [];
  for (let i = 0; i < 8; i += 2) r.push(parseInt(s.slice(i,i+2), 16));
  return new Uint8Array(r);
};

