test("alfaHt matches pinned reference vectors", () => {
  for (const [seed, want] of Object.entries(HT_VECTORS)) {
    assert.equal(hex(alfaHt(bytes(seed))), want, `ht(${seed})`);
  }
});

test("alfaHt is literally w6(0x41AA42BB, 0x22BA9A31)", () => {
  for (const seed of SEEDS) {
    const a = hex(alfaHt(bytes(seed)));
    const b = hex(alfaW6(bytes(seed), 0x41AA42BB, 0x22BA9A31));
    assert.equal(a, b, `equivalence at seed ${seed}`);
  }
});

