test("alfaW6By matches pinned vectors for the four dispatcher-mapped wrappers", () => {
  for (const [name, vec] of Object.entries(W6_VECTORS)) {
    assert.ok(name in AOBD_W6, `wrapper ${name} present in AOBD_W6`);
    for (const [seed, want] of Object.entries(vec)) {
      assert.equal(hex(alfaW6By(bytes(seed), name)), want, `w6/${name}(${seed})`);
    }
  }
});

test("alfaW6By returns null for unknown wrapper names", () => {
  assert.equal(alfaW6By(bytes("DEADBEEF"), "this_does_not_exist"), null);
});

// ─── Avalanche ────────────────────────────────────────────────────────
function avalanche(fn, bytewise=true) {
  const baseSeed = new Uint8Array([0xA1,0xB2,0xC3,0xD4]);
  const base = fn(baseSeed);
  let total = 0, n = 0;
  for (let bit = 0; bit < 32; bit++) {
    const flipped = new Uint8Array(baseSeed);
    flipped[bit >>> 3] ^= 1 << (7 - (bit & 7));
    const out = fn(flipped);
    let d = 0;
    for (let i = 0; i < 4; i++) {
      let x = (out[i] ^ base[i]) & 0xFF;
      while (x) { d += x & 1; x >>>= 1; }
    }
    total += d; n++;
  }
  return total / n;
}

test("alfaF avalanche is in [14.5, 17.5] bits", () => {
  const a = avalanche(alfaF);
  assert.ok(a >= 14.5 && a <= 17.5, `alfaF avalanche=${a.toFixed(2)} out of range`);
});

test("alfaAo avalanche is in [14.5, 17.5] bits", () => {
  const a = avalanche(alfaAo);
  assert.ok(a >= 14.5 && a <= 17.5, `alfaAo avalanche=${a.toFixed(2)} out of range`);
});

test("alfaW6 avalanche stays ≤ 4 bits (linear cipher signature)", () => {
  // Per the README: ~1.41 bits flipped per single-bit input perturbation.
  // We give a generous ceiling (4 bits) so the test isn't fragile across
  // different (r, s) pairs but still trips if w6 silently turns into XTEA.
  for (const name of ["tt","tu","tv","ez"]) {
    const a = avalanche((sb) => alfaW6By(sb, name));
    assert.ok(a <= 4.0, `w6/${name} avalanche=${a.toFixed(2)} too high — likely no longer linear`);
  }
});

// ─── Wiring ───────────────────────────────────────────────────────────
test("ALGOS registry exposes the AlfaOBD entries", () => {
  const ids = ALGOS.map(a => a.id);
  for (const id of ["alfa_ht","alfa_f","alfa_ao","alfa_w6_tt","alfa_w6_tu","alfa_w6_tv","alfa_w6_ez"]) {
    assert.ok(ids.includes(id), `missing ALGOS id ${id}`);
  }
  // None of the new entries may carry a demo flag.
  for (const a of ALGOS.filter(x => x.id.startsWith("alfa_"))) {
    assert.equal(a.demo, undefined, `${a.id} must not carry demo flag`);
    assert.ok(!/demo/i.test(a.n), `${a.id} label contains DEMO`);
  }
});

test("UNLOCK_FALLBACK puts alfa_ao directly after CDA6 and lists w6 wrappers at the tail", () => {
  // Order matters: CDA6 first (default for body-bus), then alfa_ao so
  // UCONNECT/RADIO_FGA at access level 5 resolves before we burn an
  // attempt on the GPEC XOR family. The four dispatcher-mapped w6
  // wrappers come last so a body-bus ECU that turns out to be one of
  // them still gets covered without a per-module override.
  assert.equal(UNLOCK_FALLBACK[0], "cda6");
  assert.equal(UNLOCK_FALLBACK[1], "alfa_ao");
  for (const w of ["alfa_w6_tt","alfa_w6_tu","alfa_w6_tv","alfa_w6_ez"]) {
    assert.ok(UNLOCK_FALLBACK.includes(w), `UNLOCK_FALLBACK missing ${w}`);
  }
  // GPEC family still present and ordered after alfa_ao.
  const aoIdx = UNLOCK_FALLBACK.indexOf("alfa_ao");
  const gpec2Idx = UNLOCK_FALLBACK.indexOf("gpec2");
  assert.ok(aoIdx < gpec2Idx, "alfa_ao must come before gpec2");
});

test("pickUnlockChain composes the body-bus chain with alfa_ao + w6 wrappers", () => {
  // Body-bus example: BCM at 0x742 with code 'BCM' (cda6 preferred).
  const chain = pickUnlockChain(0x742, "BCM");
  // Preferred algorithm (cda6) leads, then alfa_ao, then GPEC, then w6 tail.
  assert.equal(chain[0], "cda6");
  assert.equal(chain[1], "alfa_ao");
  assert.ok(chain.includes("gpec2"));
  for (const w of ["alfa_w6_tt","alfa_w6_tu","alfa_w6_tv","alfa_w6_ez"]) {
    assert.ok(chain.includes(w), `chain missing ${w}`);
  }
  // No duplicates.
  assert.equal(new Set(chain).size, chain.length);
});

test("pickUnlockChain on the SGW gateway stays XTEA-only — no alfa_* fallback", () => {
  const chain = pickUnlockChain(0x74F, "SGW");
  assert.deepEqual(chain, ["xtea_sgw"]);
});

test("ALGOS exposes a single AlfaOBD w6 (custom) entry", () => {
  // The reviewer-required "wrapper-or-(r,s)" entry. The fn intentionally
  // returns 0 — SeedTab is the source of truth for the actual compute,
  // because the (r, s) pair lives in UI state, not the registry.
  const custom = ALGOS.find(a => a.id === "alfa_w6_custom");
  assert.ok(custom, "alfa_w6_custom missing from ALGOS");
  assert.equal(custom.custom, "alfa_w6", "custom marker missing");
  assert.equal(custom.fn(0xDEADBEEF), 0, "bare fn must return 0 (UI handles params)");
  assert.ok(!/demo/i.test(custom.n));
});

test("unlockKey routes alfa_* ids byte-natively (and matches pinned vectors)", () => {
  const seedU32 = 0x12345678 >>> 0;
  // Round-tripping ht/ao through u32 is safe (BE pack + BE unpack).
  assert.equal(
    unlockKey("alfa_ht", seedU32).toString(16).toUpperCase().padStart(8,"0"),
    HT_VECTORS["12345678"]
  );
  assert.equal(
    unlockKey("alfa_ao", seedU32).toString(16).toUpperCase().padStart(8,"0"),
    AO_VECTORS["12345678"]
  );
});

test("unlockKeyBytes preserves alfa_f LE byte ordering", () => {
  // The whole reason unlockKeyBytes exists: alfa_f packs LE, so feeding
  // raw bytes through here must NOT mirror what unlockKey(u32) does for
  // alfa_f when the seed has any byte asymmetry.
  const sb = bytes("12345678");
  const out = unlockKeyBytes("alfa_f", sb);
  const got = out.map(b => b.toString(16).padStart(2,"0")).join("").toUpperCase();
  assert.equal(got, F_VECTORS["12345678"]);
});

test("unlockKeyBytes resolves alfa_w6/<name> wrappers from the catalog", () => {
  const out = unlockKeyBytes("alfa_w6/tt", bytes("DEADBEEF"));
  const got = out.map(b => b.toString(16).padStart(2,"0")).join("").toUpperCase();
  assert.equal(got, W6_VECTORS.tt["DEADBEEF"]);
  // Unknown wrapper → null.
  assert.equal(unlockKeyBytes("alfa_w6/zzz_unknown", bytes("00000000")), null);
});
